selector_to_html = {"a[href=\"motion_correction.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Registration<a class=\"headerlink\" href=\"#registration\" title=\"Link to this heading\">#</a></h1><p>Correct for rigid/non-rigid movement</p>", "a[href=\"#cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">CNMF<a class=\"headerlink\" href=\"#cnmf\" title=\"Link to this heading\">#</a></h1><p>Run the CaImAn <code class=\"docutils literal notranslate\"><span class=\"pre\">CNMF</span></code> algorithm using the mcorr output obtained in the last processing step.</p>", "a[href=\"#extras\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Extras<a class=\"headerlink\" href=\"#extras\" title=\"Link to this heading\">#</a></h1>", "a[href=\"#optiona-adjust-parameters-and-rerun-cnmf\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">(Optiona) Adjust parameters and rerun CNMF<a class=\"headerlink\" href=\"#optiona-adjust-parameters-and-rerun-cnmf\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#segmentation\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Segmentation<a class=\"headerlink\" href=\"#segmentation\" title=\"Link to this heading\">#</a></h1><p>Extract neuronal locations and planar time-traces.</p>", "a[href=\"#run-cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Run CNMF<a class=\"headerlink\" href=\"#run-cnmf\" title=\"Link to this heading\">#</a></h1><p>The API is identical to running mcorr.</p><p>You can provide the mcorr item row to <code class=\"docutils literal notranslate\"><span class=\"pre\">input_movie_path</span></code> and it will resolve the path of the input movie from the entry in the DataFrame.</p>", "a[href=\"#pick-the-best-parameter-set\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Pick the best parameter set<a class=\"headerlink\" href=\"#pick-the-best-parameter-set\" title=\"Link to this heading\">#</a></h1><h2>Adjust quality metrics based on evaluation parameters<a class=\"headerlink\" href=\"#adjust-quality-metrics-based-on-evaluation-parameters\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#view-accepted-neurons-on-a-summary-image\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">View accepted neurons on a summary image<a class=\"headerlink\" href=\"#view-accepted-neurons-on-a-summary-image\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#run-the-cnmf-batch-items\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Run the <code class=\"docutils literal notranslate\"><span class=\"pre\">cnmf</span></code> batch items<a class=\"headerlink\" href=\"#run-the-cnmf-batch-items\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#adjust-quality-metrics-based-on-evaluation-parameters\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Adjust quality metrics based on evaluation parameters<a class=\"headerlink\" href=\"#adjust-quality-metrics-based-on-evaluation-parameters\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#the-most-important-step\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">The most important step<a class=\"headerlink\" href=\"#the-most-important-step\" title=\"Link to this heading\">#</a></h2><p>We need to tell CaImAn our neuron size, and how many neurons to expect.</p>", "a[href=\"#checking-for-an-errors\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Checking for an errors<a class=\"headerlink\" href=\"#checking-for-an-errors\" title=\"Link to this heading\">#</a></h2><p>After a batch run, check the results to make sure the outputs do not contain a \u201ctraceback\u201d error.</p><p>An error-free processing run will yield \u201cNone\u201d in the cell below. Otherwise, an error will be printed.</p>", "a[href=\"#parameters\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Parameters<a class=\"headerlink\" href=\"#parameters\" title=\"Link to this heading\">#</a></h2><p>In general in Caiman, estimators are first initialized with a set of parameters, and then they are fit against actual data in a separate step.</p><p>In this section, we\u2019ll define a <code class=\"docutils literal notranslate\"><span class=\"pre\">parameters</span></code> object that will subsequently be used to initialize our different estimators.</p>", "a[href=\"#evaluate-cnmf-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Evaluate CNMF outputs<a class=\"headerlink\" href=\"#evaluate-cnmf-outputs\" title=\"Link to this heading\">#</a></h1><p>Similar to mcorr, you can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> API to fetch the outputs.</p><p><a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/cnmf.html\">API reference for mesmerize-CNMF</a>\n<a class=\"reference external\" href=\"https://caiman.readthedocs.io/en/latest/Getting_Started.html#parameters\">API reference for caiman-CNMF</a></p>", "a[href=\"#parameter-gridsearch\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Parameter Gridsearch<a class=\"headerlink\" href=\"#parameter-gridsearch\" title=\"Link to this heading\">#</a></h1><p>Once you have a close approximation for a value of <code class=\"docutils literal notranslate\"><span class=\"pre\">K</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">rf</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">stride</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">gSig</span></code>, we can further tune these values with a grid-search.</p>", "a[href=\"#data-path-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Data path setup<a class=\"headerlink\" href=\"#data-path-setup\" title=\"Link to this heading\">#</a></h2><p>Data setup is similar to <a class=\"reference internal\" href=\"motion_correction.html\"><span class=\"std std-doc\">motion_correction notebook</span></a>.</p>", "a[href=\"#evaluate-cnmf-results\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Evaluate CNMF Results<a class=\"headerlink\" href=\"#evaluate-cnmf-results\" title=\"Link to this heading\">#</a></h2><p>The next step is to adjust evaluation parameters, <code class=\"docutils literal notranslate\"><span class=\"pre\">min_SNR</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">rval_thr</span></code> (and <code class=\"docutils literal notranslate\"><span class=\"pre\">cnn_thr</span></code> if you used <code class=\"docutils literal notranslate\"><span class=\"pre\">use_cnn=True</span></code>).</p><p>These parameters <strong>will not compensate for poorly-calculated initialization parameters</strong>.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
